  1	import React, { FC } from 'react';
  2	
  3	import { modelToRef, TemplateModel } from '@kubevirt-ui/kubevirt-api/console';
  4	import { V1beta1DataSource } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
  5	import ListPageFilter from '@kubevirt-utils/components/ListPageFilter/ListPageFilter';
  6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  7	import { ListPageProps } from '@kubevirt-utils/utils/types';
  8	import { isEmpty } from '@kubevirt-utils/utils/utils';
  9	import {
 10	  K8sResourceCommon,
 11	  ListPageBody,
 12	  ListPageHeader,
 13	  useListPageFilter,
 14	  VirtualizedTable,
 15	} from '@openshift-console/dynamic-plugin-sdk';
 16	import { Stack, StackItem } from '@patternfly/react-core';
 17	
 18	import VirtualMachineTemplatesCreateButton from './components/VirtualMachineTemplatesCreateButton/VirtualMachineTemplatesCreateButton';
 19	import VirtualMachineTemplatesEmptyState from './components/VirtualMachineTemplatesEmptyState/VirtualMachineTemplatesEmptyState';
 20	import VirtualMachineTemplatesRow from './components/VirtualMachineTemplatesRow';
 21	import VirtualMachineTemplateSupport from './components/VirtualMachineTemplateSupport/VirtualMachineTemplateSupport';
 22	import useHideDeprecatedTemplates from './hooks/useHideDeprecatedTemplates';
 23	import { useTemplatesWithAvailableSource } from './hooks/useTemplatesWithAvailableSource';
 24	import useVirtualMachineTemplatesColumns from './hooks/useVirtualMachineTemplatesColumns';
 25	import useVirtualMachineTemplatesFilters from './hooks/useVirtualMachineTemplatesFilters';
 26	
 27	const VirtualMachineTemplatesList: FC<ListPageProps> = ({
 28	  fieldSelector,
 29	  hideColumnManagement,
 30	  hideNameLabelFilters,
 31	  hideTextFilter,
 32	  nameFilter,
 33	  namespace,
 34	  selector,
 35	  showTitle,
 36	}) => {
 37	  const { t } = useKubevirtTranslation();
 38	  const {
 39	    availableDatasources,
 40	    availableTemplatesUID,
 41	    bootSourcesLoaded,
 42	    cloneInProgressDatasources,
 43	    error,
 44	    loaded,
 45	    templates,
 46	  } = useTemplatesWithAvailableSource({
 47	    fieldSelector,
 48	    namespace,
 49	    onlyAvailable: false,
 50	    onlyDefault: false,
 51	    selector,
 52	  });
 53	  const filters = useVirtualMachineTemplatesFilters(availableTemplatesUID);
 54	  const [data, filteredData, onFilterChange] = useListPageFilter(templates, filters, {
 55	    name: { selected: [nameFilter] },
 56	  });
 57	
 58	  const [columns, activeColumns, loadedColumns] = useVirtualMachineTemplatesColumns(namespace);
 59	
 60	  const templatesLoaded = loaded && bootSourcesLoaded;
 61	
 62	  useHideDeprecatedTemplates(onFilterChange);
 63	
 64	  if (templatesLoaded && isEmpty(data)) {
 65	    return <VirtualMachineTemplatesEmptyState namespace={namespace} />;
 66	  }
 67	
 68	  return (
 69	    <>
 70	      <ListPageHeader title={!(showTitle === false) && t('VirtualMachine Templates')}>
 71	        <VirtualMachineTemplatesCreateButton namespace={namespace} />
 72	      </ListPageHeader>
 73	      <ListPageBody>
 74	        <Stack hasGutter>
 75	          <StackItem>
 76	            <VirtualMachineTemplateSupport />
 77	          </StackItem>
 78	          <StackItem>
 79	            <ListPageFilter
 80	              columnLayout={{
 81	                columns: columns?.map(({ additional, id, title }) => ({
 82	                  additional,
 83	                  id,
 84	                  title,
 85	                })),
 86	                id: modelToRef(TemplateModel),
 87	                selectedColumns: new Set(activeColumns?.map((col) => col?.id)),
 88	                type: t('Template'),
 89	              }}
 90	              data={data}
 91	              hideColumnManagement={hideColumnManagement}
 92	              hideLabelFilter={hideTextFilter}
 93	              hideNameLabelFilters={hideNameLabelFilters}
 94	              loaded={templatesLoaded && loadedColumns}
 95	              onFilterChange={onFilterChange}
 96	              rowFilters={filters}
 97	            />
 98	            <VirtualizedTable<
 99	              K8sResourceCommon,
100	              {
101	                availableDatasources: Record<string, V1beta1DataSource>;
102	                availableTemplatesUID: Set<string>;
103	                cloneInProgressDatasources: Record<string, V1beta1DataSource>;
104	              }
105	            >
106	              EmptyMsg={() => (
107	                <div className="pf-v6-u-text-align-center" id="no-templates-msg">
108	                  {t('No templates found')}
109	                </div>
110	              )}
111	              columns={activeColumns}
112	              data={filteredData}
113	              loaded={templatesLoaded && loadedColumns}
114	              loadError={error}
115	              Row={VirtualMachineTemplatesRow}
116	              rowData={{ availableDatasources, availableTemplatesUID, cloneInProgressDatasources }}
117	              unfilteredData={data}
118	            />
119	          </StackItem>
120	        </Stack>
121	      </ListPageBody>
122	    </>
123	  );
124	};
125	
126	export default VirtualMachineTemplatesList;

